// One-off seed for the CoAction CRM base. Fill CONFIG, execute once, DELETE this workflow
// afterwards (the token lives in this code). Re-running creates duplicates.
const CONFIG = {
  url: 'http://localhost:8080',          // NocoDB URL as seen FROM n8n (docker: http://nocodb:8080)
  token: 'PASTE_NOCODB_API_TOKEN',
  baseId: 'PASTE_BASE_ID',
  emails: {
    przemek: 'przemek@example.com', dorota: 'dorota@example.com',
    aleksandra: 'aleksandra@example.com', paulina: 'paulina@example.com',
    kasia: 'kasia@example.com',
  },
};

const TABLES = ['companies','leads','participants','meetings','tasks',
                'task_templates','projects','activities','testimonials'];
const log = [];
const req = (method, path, body) => this.helpers.httpRequest({
  method, url: CONFIG.url.replace(/\/$/, '') + path,
  headers: { 'xc-token': CONFIG.token }, body, json: true,
});

// --- resolve table ids + link-field ids from meta API -----------------------
const TBL = {}, LNK = {};
const tl = await req('GET', `/api/v2/meta/bases/${CONFIG.baseId}/tables`);
for (const t of tl.list || []) {
  const title = t.title.trim().toLowerCase();
  if (TABLES.includes(title)) TBL[title] = t.id;
}
const missing = TABLES.filter(t => !TBL[t]);
if (missing.length) throw new Error('Tables not found (check titles): ' + missing.join(', '));
for (const [title, tid] of Object.entries(TBL)) {
  LNK[title] = {};
  let cols = [];
  try { cols = (await req('GET', `/api/v2/meta/tables/${tid}/columns`)).list || []; }
  catch (e) { cols = (await req('GET', `/api/v2/meta/tables/${tid}`)).columns || []; }
  for (const c of cols)
    if (c.uidt === 'Links' || c.uidt === 'LinkToAnotherRecord')
      LNK[title][c.title.trim().toLowerCase()] = c.id;
}

// --- helpers -----------------------------------------------------------------
async function create(table, record) {
  const res = await req('POST', `/api/v2/tables/${TBL[table]}/records`, record);
  const id = res.Id ?? res.id ?? (Array.isArray(res) && res[0] && res[0].Id);
  log.push(`+ ${table}#${id}: ${record.name || record.title || record.contact_name || record.full_name || record.summary || ''}`);
  return id;
}
async function link(table, field, recordId, targets) {
  const fid = LNK[table][field];
  if (!fid) { log.push(`! link field '${field}' missing on '${table}' (have: ${Object.keys(LNK[table])})`); return; }
  const ids = Array.isArray(targets) ? targets : [targets];
  await req('POST', `/api/v2/tables/${TBL[table]}/links/${fid}/records/${recordId}`,
            ids.map(i => ({ Id: i })));
  log.push(`  ~ ${table}#${recordId}.${field} -> [${ids}]`);
}
const day = o => { const d = new Date(Date.now() + o * 864e5); return d.toISOString().slice(0, 10); };
const dt  = (o, h) => { const d = new Date(Date.now() + o * 864e5); d.setHours(h, 0, 0, 0); return d.toISOString(); };
const E = CONFIG.emails;

// --- projects ------------------------------------------------------------------
const prjMkt = await create('projects', { name: 'Marketing', team: 'marketing', active: true });
const prjSal = await create('projects', { name: 'Sprzedaż', team: 'sales', active: true });
const prjOps = await create('projects', { name: 'Wewnętrzne', team: 'ops', active: true });

// --- companies -------------------------------------------------------------------
const cTechflow = await create('companies', { name: 'TechFlow Sp. z o.o.',
  domains: 'techflow.pl, techflow.io', industry: 'IT', size: '51-250',
  notes: 'Software house, ~120 devs. English used with US clients.' });
await create('companies', { name: 'Baltic Logistics S.A.', domains: 'balticlogistics.pl',
  industry: 'Logistyka', size: '250+', notes: 'Freight forwarding, formal tone.' });

// --- testimonials ------------------------------------------------------------------
const tIt = await create('testimonials', { title: 'Case study: zespół dev w US-owym projekcie',
  client_name: 'Anonimizowany software house', industry: 'IT', type: 'case_study',
  variant: 'english_for_it', active: true,
  content: '12 developers, 6 months, avg progress +0.8 CEFR sub-level.' });
const tB2c = await create('testimonials', { title: 'Opinia: awans po roku nauki',
  client_name: 'Senior Frontend Developer', industry: 'IT', type: 'testimonial',
  variant: 'business_english', active: true,
  content: 'After a year I finally lead client calls without stress.' });
await create('testimonials', { title: 'Case study: dział operacji w logistyce',
  client_name: 'Firma TSL', industry: 'Logistyka', type: 'case_study',
  variant: 'english_business_skills', active: true,
  content: '18 participants across 3 groups, negotiations focus.' });

// --- L1: B2C, full pipeline (the 'Piotr' scenario) ----------------------------------
const l1 = await create('leads', { contact_name: 'Piotr Zieliński',
  contact_email: 'piotr.zielinski@gmail.com', contact_phone: '+48 600 100 200',
  type: 'B2C', owner: E.przemek, source: 'google', contact_channel: 'formularz',
  qualification: 'SQL', stage: 'offer_discussed', state: 'open', value: 5400,
  industry: 'IT', offer_prep_status: 'draft_ready', company_match_status: 'none',
  training_goals: 'Lead client calls confidently; B2.4 -> C1 in 12 months.',
  notes: 'Wants 2x/week evening sessions.', offer_sent_at: day(-3) });
await link('leads', 'selected_testimonials', l1, [tIt, tB2c]);

const p1 = await create('participants', { full_name: 'Piotr Zieliński',
  position: 'Senior Frontend Developer', cefr_overall: 'B2.4', cefr_range: 'B2.5',
  cefr_accuracy: 'B2.2', cefr_fluency: 'B2.3', cefr_communication: 'B2.6',
  audit_notes: 'Strong vocabulary, hesitates under pressure.',
  needs_summary: 'Client demos, sprint reviews, US stakeholders.',
  assigned_methodologist: E.aleksandra });
await link('participants', 'lead', p1, l1);

const m1 = await create('meetings', { title: 'Discovery — Piotr Zieliński',
  type: 'discovery', starts_at: dt(-4, 14), ends_at: dt(-4, 15), owner: E.przemek,
  status: 'done', processing_status: 'ai_accepted',
  transcript: '[SAMPLE] Przemek: What situations are hardest? Piotr: Client demos...',
  ai_analysis: '[SAMPLE AI DRAFT] Goals: confident client communication. Suggested: Business English 2x/week.',
  notes: 'Very motivated, budget confirmed.', outcome: 'Proceed to offer.' });
await link('meetings', 'lead', m1, l1);
await link('meetings', 'participant', m1, p1);

// --- L2: B2B TechFlow, 3 participants -------------------------------------------------
const l2 = await create('leads', { contact_name: 'Marta Kowal',
  contact_email: 'marta.kowal@techflow.pl', contact_phone: '+48 601 200 300',
  type: 'B2B', owner: E.przemek, source: 'polecenie', contact_channel: 'email',
  qualification: 'SQL', stage: 'audit', state: 'open', value: 38000, industry: 'IT',
  offer_prep_status: 'none', company_match_status: 'confirmed',
  notes: 'HR Manager, buying for the delivery team - NOT a participant herself.' });
await link('leads', 'company', l2, cTechflow);
const ppl = [];
for (const [name, pos, extra] of [
  ['Jan Dąbrowski', 'Team Lead', { cefr_overall: 'B1.8', audit_notes: 'Fluent but inaccurate.' }],
  ['Ola Wrona', 'QA Engineer', {}], ['Tomasz Lis', 'Backend Developer', {}]]) {
  const p = await create('participants', { full_name: name, position: pos,
    assigned_methodologist: E.dorota, ...extra });
  await link('participants', 'lead', p, l2);
  await link('participants', 'company', p, cTechflow);
  ppl.push(p);
}
const m2 = await create('meetings', { title: 'Discovery — TechFlow (Marta Kowal)',
  type: 'discovery', starts_at: dt(-10, 10), owner: E.przemek, status: 'done',
  processing_status: 'none', notes: '3 people to audit, budget 35-40k.' });
await link('meetings', 'lead', m2, l2);
const m3 = await create('meetings', { title: 'Audyt — Jan Dąbrowski', type: 'audit',
  starts_at: dt(2, 9), owner: E.dorota, status: 'scheduled', processing_status: 'none' });
await link('meetings', 'lead', m3, l2);
await link('meetings', 'participant', m3, ppl[0]);

// --- L3: B2C pair ---------------------------------------------------------------------
const l3 = await create('leads', { contact_name: 'Adam Nowicki',
  contact_email: 'adam.nowicki@wp.pl', type: 'B2C', owner: E.przemek,
  source: 'polecenie', contact_channel: 'telefon', qualification: 'MQL',
  stage: 'new', state: 'open', value: 9600, offer_prep_status: 'none',
  company_match_status: 'none', notes: 'Lessons together with his wife.' });
for (const [name, pos] of [['Adam Nowicki', 'Accountant'], ['Ewa Nowicka', 'Project Manager']]) {
  const p = await create('participants', { full_name: name, position: pos,
    assigned_methodologist: E.aleksandra });
  await link('participants', 'lead', p, l3);
}

// --- L4: returning company (W5 case) ----------------------------------------------------
const l4 = await create('leads', { contact_name: 'Karol Wiśniewski',
  contact_email: 'karol.wisniewski@techflow.pl', type: 'B2B', owner: E.przemek,
  source: 'powrot_klienta', contact_channel: 'email', qualification: 'MQL',
  stage: 'discovery_scheduled', state: 'open', offer_prep_status: 'none',
  company_match_status: 'pending_confirmation',
  notes: 'Sales dept this time - different budget owner.' });
await link('leads', 'company', l4, cTechflow);
const m4 = await create('meetings', { title: 'Discovery — Karol Wiśniewski (TechFlow sales)',
  type: 'discovery', starts_at: dt(3, 13), owner: E.przemek, status: 'scheduled',
  processing_status: 'none' });
await link('meetings', 'lead', m4, l4);

// --- task templates -----------------------------------------------------------------------
const tt1 = await create('task_templates', { title: 'Raport marketingowy {{month}}',
  assignee: E.kasia, rrule: 'FREQ=WEEKLY;BYDAY=MO', due_offset_days: 1,
  description: 'Weekly channels summary for the CEO.', active: true });
const tt2 = await create('task_templates', { title: 'Fakturowanie klientów {{month}}',
  assignee: E.paulina, rrule: 'FREQ=MONTHLY;BYMONTHDAY=1', due_offset_days: 3,
  description: 'Issue invoices for all active trainings.', active: true });
await link('task_templates', 'project', tt1, prjMkt);
await link('task_templates', 'project', tt2, prjOps);

// --- tasks -----------------------------------------------------------------------------------
const taskRows = [
  [{ title: 'Offer draft ready - assemble the offer: Piotr Zieliński', status: 'todo',
     priority: 'high', assignee: E.przemek, created_by_flow: 'W6b',
     description: `lead:${l1}`, due_date: day(1) }, prjSal, l1],
  [{ title: 'Confirm company match: TechFlow (karol.wisniewski@techflow.pl)', status: 'todo',
     priority: 'normal', assignee: E.przemek, created_by_flow: 'W5',
     description: `lead:${l4}`, due_date: day(1) }, prjSal, l4],
  [{ title: 'Przygotować audyty dla TechFlow (3 osoby)', status: 'in_progress',
     priority: 'high', assignee: E.dorota, description: `lead:${l2}`, due_date: day(2) }, prjSal, l2],
  [{ title: 'Zadzwonić do Adama Nowickiego - termin discovery', status: 'todo',
     priority: 'normal', assignee: E.przemek, description: `lead:${l3}`, due_date: day(0) }, prjSal, l3],
  [{ title: 'Newsletter lipcowy - draft', status: 'todo', priority: 'normal',
     assignee: E.kasia, due_date: day(4) }, prjMkt, null],
  [{ title: 'Define training goals: Piotr Zieliński', status: 'done', priority: 'normal',
     assignee: E.aleksandra, created_by_flow: 'W6a', description: `lead:${l1}`,
     due_date: day(-2) }, prjSal, l1],
];
for (const [rec, prj, leadId] of taskRows) {
  const t = await create('tasks', rec);
  await link('tasks', 'project', t, prj);
  if (leadId) await link('tasks', 'lead', t, leadId);
}
const tRec = await create('tasks', { title: `Raport marketingowy ${day(0).slice(0, 7)}`,
  status: 'todo', priority: 'normal', assignee: E.kasia, created_by_flow: 'W1',
  due_date: day(1) });
await link('tasks', 'template', tRec, tt1);
await link('tasks', 'project', tRec, prjMkt);

// --- activities (the 'Piotr' timeline + W5 entry) ----------------------------------------------
const acts = [
  ['Lead created from Tally form: Piotr Zieliński', 'lead_created', 'W4', 'system', l1],
  ['Task for Przemek: Schedule discovery call', 'task_created', 'W4', 'system', l1],
  ['Transcript pasted, analysis requested', 'transcript_added', 'W6a', E.przemek, l1],
  ['AI analysis ready for meeting: Discovery — Piotr Zieliński', 'ai_analysis_done', 'W6a', 'system', l1],
  ['AI draft accepted, goals requested (Piotr Zieliński)', 'ai_accepted', 'W6a', E.przemek, l1],
  ['Goals saved, testimonials requested (Piotr Zieliński)', 'goals_provided', 'W6b', E.aleksandra, l1],
  ['2 testimonial(s) linked, offer draft ready (Piotr Zieliński)', 'testimonials_provided', 'W6b', E.przemek, l1],
  ['Company match suggested: TechFlow Sp. z o.o. (techflow.pl)', 'company_match_suggested', 'W5', 'system', l4],
];
for (const [summary, type, flow, by, leadId] of acts) {
